(window.webpackJsonp=window.webpackJsonp||[]).push([[876],{856:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">position</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">m</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxDistance = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">position, m</span>) </span>{\\n    position.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a-b)\\n    <span class=\\"hljs-keyword\\">let</span> maxGap=position[position.length<span class=\\"hljs-number\\">-1</span>]-position[<span class=\\"hljs-number\\">0</span>]\\n    <span class=\\"hljs-keyword\\">if</span>(m===<span class=\\"hljs-number\\">2</span>)<span class=\\"hljs-keyword\\">return</span> maxGap\\n    <span class=\\"hljs-keyword\\">let</span> l=<span class=\\"hljs-number\\">1</span>,r=maxGap\\n    <span class=\\"hljs-keyword\\">while</span>(l&lt;r){\\n        <span class=\\"hljs-keyword\\">let</span> mid=<span class=\\"hljs-built_in\\">Math</span>.ceil((l+r)/<span class=\\"hljs-number\\">2</span>)\\n        <span class=\\"hljs-keyword\\">let</span> count=<span class=\\"hljs-number\\">1</span>\\n        <span class=\\"hljs-keyword\\">let</span> valid=<span class=\\"hljs-literal\\">false</span>\\n        <span class=\\"hljs-keyword\\">let</span> last=position[<span class=\\"hljs-number\\">0</span>]\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;position.length;i++){\\n            <span class=\\"hljs-keyword\\">if</span>(position[i]-last&gt;=mid){\\n                count++\\n                last=position[i]\\n                <span class=\\"hljs-keyword\\">if</span>(count&gt;=m){\\n                    valid=<span class=\\"hljs-literal\\">true</span>\\n                    <span class=\\"hljs-keyword\\">break</span>\\n                }\\n            }\\n        }\\n        <span class=\\"hljs-keyword\\">if</span>(valid)l=mid\\n        <span class=\\"hljs-keyword\\">else</span> r=mid<span class=\\"hljs-number\\">-1</span>\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> r\\n};\\n</code></pre>\\n"],"titleSlug":"magnetic-force-between-two-balls","hasThinking":false,"content":"<p>\u5728\u4ee3\u53f7\u4e3a C-137 \u7684\u5730\u7403\u4e0a\uff0cRick \u53d1\u73b0\u5982\u679c\u4ed6\u5c06\u4e24\u4e2a\u7403\u653e\u5728\u4ed6\u65b0\u53d1\u660e\u7684\u7bee\u5b50\u91cc\uff0c\u5b83\u4eec\u4e4b\u95f4\u4f1a\u5f62\u6210\u7279\u6b8a\u5f62\u5f0f\u7684\u78c1\u529b\u3002Rick \u6709&nbsp;<code>n</code>&nbsp;\u4e2a\u7a7a\u7684\u7bee\u5b50\uff0c\u7b2c&nbsp;<code>i</code>&nbsp;\u4e2a\u7bee\u5b50\u7684\u4f4d\u7f6e\u5728&nbsp;<code>position[i]</code>&nbsp;\uff0cMorty&nbsp;\u60f3\u628a&nbsp;<code>m</code>&nbsp;\u4e2a\u7403\u653e\u5230\u8fd9\u4e9b\u7bee\u5b50\u91cc\uff0c\u4f7f\u5f97\u4efb\u610f\u4e24\u7403\u95f4&nbsp;<strong>\u6700\u5c0f\u78c1\u529b</strong>&nbsp;\u6700\u5927\u3002</p>\\n\\n<p>\u5df2\u77e5\u4e24\u4e2a\u7403\u5982\u679c\u5206\u522b\u4f4d\u4e8e&nbsp;<code>x</code>&nbsp;\u548c&nbsp;<code>y</code>&nbsp;\uff0c\u90a3\u4e48\u5b83\u4eec\u4e4b\u95f4\u7684\u78c1\u529b\u4e3a&nbsp;<code>|x - y|</code>&nbsp;\u3002</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4&nbsp;<code>position</code>&nbsp;\u548c\u4e00\u4e2a\u6574\u6570&nbsp;<code>m</code>&nbsp;\uff0c\u8bf7\u4f60\u8fd4\u56de\u6700\u5927\u5316\u7684\u6700\u5c0f\u78c1\u529b\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/08/16/q3v1.jpg\\" style=\\"height: 195px; width: 562px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>position = [1,2,3,4,7], m = 3\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u5c06 3 \u4e2a\u7403\u5206\u522b\u653e\u5165\u4f4d\u4e8e 1\uff0c4 \u548c 7 \u7684\u4e09\u4e2a\u7bee\u5b50\uff0c\u4e24\u7403\u95f4\u7684\u78c1\u529b\u5206\u522b\u4e3a [3, 3, 6]\u3002\u6700\u5c0f\u78c1\u529b\u4e3a 3 \u3002\u6211\u4eec\u6ca1\u529e\u6cd5\u8ba9\u6700\u5c0f\u78c1\u529b\u5927\u4e8e 3 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>position = [5,4,3,2,1,1000000000], m = 2\\n<strong>\u8f93\u51fa\uff1a</strong>999999999\\n<strong>\u89e3\u91ca\uff1a</strong>\u6211\u4eec\u4f7f\u7528\u4f4d\u4e8e 1 \u548c 1000000000 \u7684\u7bee\u5b50\u65f6\u6700\u5c0f\u78c1\u529b\u6700\u5927\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>n == position.length</code></li>\\n\\t<li><code>2 &lt;= n &lt;= 10^5</code></li>\\n\\t<li><code>1 &lt;= position[i] &lt;= 10^9</code></li>\\n\\t<li>\u6240\u6709&nbsp;<code>position</code>&nbsp;\u4e2d\u7684\u6574\u6570 <strong>\u4e92\u4e0d\u76f8\u540c</strong>&nbsp;\u3002</li>\\n\\t<li><code>2 &lt;= m &lt;= position.length</code></li>\\n</ul>\\n","title":"1552. \u4e24\u7403\u4e4b\u95f4\u7684\u78c1\u529b","relatedTags":["\u6570\u7ec4","\u4e8c\u5206\u67e5\u627e"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1552"}')}}]);